import{_ as e,o as l,c as r,am as i}from"./chunks/framework.4ujba3IF.js";const p=JSON.parse('{"title":"職涯歷程","description":"","frontmatter":{},"headers":[],"relativePath":"career.md","filePath":"career.md","lastUpdated":1781254545000}'),t={name:"career.md"};function n(h,a,o,d,s,c){return l(),r("div",null,[...a[0]||(a[0]=[i('<h1 id="職涯歷程" tabindex="-1">職涯歷程 <a class="header-anchor" href="#職涯歷程" aria-label="Permalink to “職涯歷程”">​</a></h1><div style="text-align:center;margin-bottom:2rem;"><h2 id="從遊戲少年到全端工程師" tabindex="-1">從遊戲少年到全端工程師 <a class="header-anchor" href="#從遊戲少年到全端工程師" aria-label="Permalink to “從遊戲少年到全端工程師”">​</a></h2><p>吳彥東的職涯發展歷程，從學生時期的自學探索到進入職場的專業成長。</p></div><hr><h2 id="時間軸" tabindex="-1">時間軸 <a class="header-anchor" href="#時間軸" aria-label="Permalink to “時間軸”">​</a></h2><h3 id="_2024-03-18-–-至今-中程資訊顧問有限公司-cmis" tabindex="-1">2024/03/18 – 至今：中程資訊顧問有限公司 (CMIS) <a class="header-anchor" href="#_2024-03-18-–-至今-中程資訊顧問有限公司-cmis" aria-label="Permalink to “2024/03/18 – 至今：中程資訊顧問有限公司 (CMIS)”">​</a></h3><p><strong>職位</strong>：軟體工程師</p><h4 id="負責內容" tabindex="-1">負責內容 <a class="header-anchor" href="#負責內容" aria-label="Permalink to “負責內容”">​</a></h4><ul><li><p><strong>ERP 系統 Web 化重構</strong>：將現有以 Delphi 2009 製作的營建工程管理資訊系統（ERP）逐步改寫為現代化的 Web 應用程式</p><ul><li><strong>後端</strong>：Golang (Echo, XORM)</li><li><strong>前端</strong>：Vue.js, Vite, PrimeVue, TailwindCSS, MasterCSS</li></ul></li><li><p><strong>系統維護開發</strong>：負責 Delphi 2009 的兩個系統維護</p><ul><li>CMIS 整合桌面資訊系統</li><li>CMIS 銷售前置分析系統</li></ul></li></ul><h4 id="技術棧" tabindex="-1">技術棧 <a class="header-anchor" href="#技術棧" aria-label="Permalink to “技術棧”">​</a></h4><table tabindex="0"><thead><tr><th>前端技術</th><th>後端技術</th></tr></thead><tbody><tr><td>Vue.js v3.5.29</td><td>Go (Golang) v1.26.0</td></tr><tr><td>Vite v7.2.6</td><td>Echo v5.0.4</td></tr><tr><td>PrimeVue v4.5.4</td><td>XORM v1.3.11</td></tr><tr><td>TailwindCSS v4.1.18</td><td>Delphi 2009</td></tr><tr><td>MasterCSS v1.37.8</td><td></td></tr><tr><td>Axios v1.13.5</td><td></td></tr></tbody></table><h4 id="工作成就" tabindex="-1">工作成就 <a class="header-anchor" href="#工作成就" aria-label="Permalink to “工作成就”">​</a></h4><ul><li>成功將傳統 Delphi 桌面應用轉型為現代化 Web 應用</li><li>建立完整的前後端開發流程</li><li>維護並擴展現有系統功能</li></ul><hr><h3 id="_2023-09-19-–-2023-12-31-軍事訓練役" tabindex="-1">2023/09/19 – 2023/12/31：軍事訓練役 <a class="header-anchor" href="#_2023-09-19-–-2023-12-31-軍事訓練役" aria-label="Permalink to “2023/09/19 – 2023/12/31：軍事訓練役”">​</a></h3><p><strong>服役單位</strong>：陸軍（4 個月軍事訓練役）</p><ul><li>2023 年 9 月 19 日入伍</li><li>2023 年 12 月 31 日結訓</li></ul><p>在服役期間體驗了嚴格的軍事訓練，培養了紀律性與團隊合作精神。</p><hr><h3 id="_2019-–-2023-國立高雄科技大學-nkust" tabindex="-1">2019 – 2023：國立高雄科技大學 (NKUST) <a class="header-anchor" href="#_2019-–-2023-國立高雄科技大學-nkust" aria-label="Permalink to “2019 – 2023：國立高雄科技大學 (NKUST)”">​</a></h3><p><strong>科系</strong>：資訊工程系（建工校區）</p><p>就讀於國立高雄科技大學資訊工程系，接受扎實的電腦科學與軟體工程訓練。</p><h4 id="學習內容" tabindex="-1">學習內容 <a class="header-anchor" href="#學習內容" aria-label="Permalink to “學習內容”">​</a></h4><ul><li>資料結構與演算法</li><li>資料庫系統</li><li>電腦網路</li><li>程式設計（C, C++, Java 等）</li><li>軟體工程</li></ul><h4 id="成就" tabindex="-1">成就 <a class="header-anchor" href="#成就" aria-label="Permalink to “成就”">​</a></h4><ul><li>2023 年畢業</li><li>在學期間累積了豐富的程式設計經驗</li></ul><hr><h3 id="_2016-–-2019-臺中市私立僑泰高級中學" tabindex="-1">2016 – 2019：臺中市私立僑泰高級中學 <a class="header-anchor" href="#_2016-–-2019-臺中市私立僑泰高級中學" aria-label="Permalink to “2016 – 2019：臺中市私立僑泰高級中學”">​</a></h3><p><strong>科系</strong>：資訊科（三年甲班）</p><p>就讀於臺中市私立僑泰高級中學資訊科，深入學習了程式設計、網頁設計、資料庫管理等資訊相關課程。</p><h4 id="學習內容-1" tabindex="-1">學習內容 <a class="header-anchor" href="#學習內容-1" aria-label="Permalink to “學習內容”">​</a></h4><ul><li>程式設計</li><li>網頁設計</li><li>資料庫管理</li><li>電腦硬體維護</li></ul><h4 id="特色" tabindex="-1">特色 <a class="header-anchor" href="#特色" aria-label="Permalink to “特色”">​</a></h4><ul><li>僑泰高中資訊科以培養實務技能著稱</li><li>提供了良好的技術基礎訓練</li></ul><hr><h3 id="_2013-–-2016-大道國民中學" tabindex="-1">2013 – 2016：大道國民中學 <a class="header-anchor" href="#_2013-–-2016-大道國民中學" aria-label="Permalink to “2013 – 2016：大道國民中學”">​</a></h3><p><strong>重要成就</strong>：</p><ul><li>2016 年國中教育會考取得 <strong>3A2B</strong> 的優異成績（A++, A+, A, B++, B+）</li><li>2015 年與 2016 年，與學校國文老師 <a href="https://www.facebook.com/dadulucy" target="_blank" rel="noreferrer">鄭麗美</a> 合作，為大道國中當屆畢業生製作畢業微電影 <ul><li><a href="https://www.youtube.com/watch?v=df7rQDfLSqU" target="_blank" rel="noreferrer">2015 畢業微電影</a></li><li><a href="https://www.youtube.com/watch?v=cpNNkTnlw68" target="_blank" rel="noreferrer">2016 畢業微電影</a></li></ul></li></ul><hr><h3 id="–-2013-山陽國民小學" tabindex="-1">~ – 2013：山陽國民小學 <a class="header-anchor" href="#–-2013-山陽國民小學" aria-label="Permalink to “~ – 2013：山陽國民小學”">​</a></h3><p>2013 年畢業於山陽國小。</p><hr><h2 id="職涯發展方向" tabindex="-1">職涯發展方向 <a class="header-anchor" href="#職涯發展方向" aria-label="Permalink to “職涯發展方向”">​</a></h2><h3 id="從-delphi-到-golang-vue-js" tabindex="-1">從 Delphi 到 Golang + Vue.js <a class="header-anchor" href="#從-delphi-到-golang-vue-js" aria-label="Permalink to “從 Delphi 到 Golang + Vue.js”">​</a></h3><p>吳彥東的職涯發展呈現出清晰的技術演進路線：</p><ol><li><strong>早期（2013-2019）</strong>：透過 Minecraft 伺服器架設，自學了網路設定、Linux 系統管理、插件開發等技能</li><li><strong>學生時期（2019-2023）</strong>：在大學期間學習了正式的電腦科學知識，包括資料結構、演算法、資料庫系統等</li><li><strong>職業初期（2024-至今）</strong>：在 CMIS 擔任軟體工程師，負責將 Delphi 2009 的 ERP 系統重寫為 Golang + Vue.js 的現代化 Web 應用</li></ol><h3 id="技術轉型" tabindex="-1">技術轉型 <a class="header-anchor" href="#技術轉型" aria-label="Permalink to “技術轉型”">​</a></h3><p>從 Delphi 2009 桌面應用開發者轉型為 Golang + Vue.js 全端工程師，展現了強大的學習能力與適應能力。在工作中不斷學習新技術，成功將舊有的 ERP 系統轉型為現代化的 Web 應用。</p><hr><h2 id="未來展望" tabindex="-1">未來展望 <a class="header-anchor" href="#未來展望" aria-label="Permalink to “未來展望”">​</a></h2><ul><li><strong>持續學習</strong>：繼續深入學習新技術，特別是在 Web 開發、雲端運算等領域</li><li><strong>專案開發</strong>：參與更多大型專案，累積實戰經驗</li><li><strong>開源貢獻</strong>：持續為開源社群貢獻力量</li><li><strong>個人項目</strong>：開發更多個人興趣專案，如 Minecraft 伺服器工具、Android 應用程式等</li></ul>',50)])])}const g=e(t,[["render",n]]);export{p as __pageData,g as default};
